1	import { useEffect, useState, useRef } from 'react'
2	import { createPortal } from 'react-dom'
3	import './CardModal.css'
4	import CommentList from '../CardModal/CommentList.jsx'
5	
6	export default function CardModal({ card, onClose, onUpdate, onDelete, onAddComment = () => Promise.resolve() }) {
7	  // Edit state
8	  const [isEditingTitle, setIsEditingTitle] = useState(false)
9	  const [editTitle, setEditTitle]           = useState(card.title)
10	  const [isEditingAssignee, setIsEditingAssignee] = useState(false)
11	  const [editAssignee, setEditAssignee]     = useState(card.assignee ?? '')
12	  const [isSaving, setIsSaving]             = useState(false)
13	  const [saveError, setSaveError]           = useState(null)
14	
15	  // Delete state
16	  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false)
