18	
19	  // Focus refs
20	  const titleInputRef    = useRef(null)
21	  const assigneeInputRef = useRef(null)
22	
23	  // Focus effects
24	  useEffect(() => {
25	    if (isEditingTitle && titleInputRef.current) titleInputRef.current.focus()
26	  }, [isEditingTitle])
27	
28	  useEffect(() => {
29	    if (isEditingAssignee && assigneeInputRef.current) assigneeInputRef.current.focus()
30	  }, [isEditingAssignee])
31	
32	  // Escape key handler — replaces the original handler
33	  useEffect(() => {
34	    function onKey(e) {
35	      if (e.key !== 'Escape') return
36	      if (isEditingTitle) {
37	        setIsEditingTitle(false); setEditTitle(card.title); setSaveError(null)
38	      } else if (isEditingAssignee) {
39	        setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null)
40	      } else {
41	        onClose()
42	      }
43	    }
44	    document.addEventListener('keydown', onKey)
45	    return () => document.removeEventListener('keydown', onKey)
46	  }, [onClose, isEditingTitle, isEditingAssignee, card.title, card.assignee])
47	
48	  // Save handlers
49	  async function handleSaveTitle() {
50	    if (editTitle.trim() === '') {
51	      setSaveError('Title is required')
52	      return
53	    }
54	    setIsSaving(true); setSaveError(null)
55	    try {
56	      await onUpdate(card.id, { title: editTitle })
57	      setIsEditingTitle(false)
58	    } catch (err) {
59	      setSaveError(err.message)
60	    } finally {
61	      setIsSaving(false)
62	    }
63	  }
