212	          <button
213	            className="modal-delete"
214	            aria-label="Delete"
215	            onClick={() => setShowDeleteConfirm(true)}
216	          >
217	            Delete
218	          </button>
219	        )}
220	      </div>
221	    </div>,
222	    document.body
223	  )
224	}
