    const onUpdate = vi.fn()
    render(<CardModal card={card} onClose={vi.fn()} onUpdate={onUpdate} onDelete={vi.fn()} onAddComment={vi.fn()} />)
    fireEvent.click(screen.getByRole('button', { name: /edit title/i }))
